function AdBanner({ isPro }) {
  const [i,sI]=useState(0);
  const ads=[{t:"Premium'a Geç!",s:"Reklamsız + tüm araçlar",bg:"linear-gradient(135deg,#4338ca,#6366f1)"},{t:"%76 Tasarruf!",s:"Yıllık plan ile büyük indirim",bg:"linear-gradient(135deg,#7c3aed,#a78bfa)"}];
  useEffect(()=>{const t=setInterval(()=>sI(x=>(x+1)%ads.length),5000);return()=>clearInterval(t);},[]);
  if(isPro) return null;
  const a=ads[i];
  return <div style={{padding:"10px 14px",background:a.bg,display:"flex",alignItems:"center",gap:10,borderRadius:12,margin:"0 14px 8px",cursor:"pointer"}}><span style={{fontSize:13,fontWeight:800,color:"#fff",flex:1}}>{a.t} <span style={{fontWeight:600,opacity:0.8,fontSize:11}}>{a.s}</span></span><span style={{fontSize:9,color:"rgba(255,255,255,0.4)"}}>AD</span></div>;
}
